import { RadioButton, RadioField } from "react-aria-components"
import { getRadioStyles } from "./radio.styles"

interface RadioProps {
	readonly label?: string
	readonly value: string
	readonly isDisabled?: boolean
}

export function Radio({ label, value, isDisabled = false }: RadioProps) {
	const styles = getRadioStyles()

	return (
		<RadioField value={value} isDisabled={isDisabled} className={styles.field}>
			<RadioButton className={styles.button}>
				{({ isSelected, isDisabled: dis, isInvalid }) => (
					<>
						<div className={styles.indicator({ isSelected, isDisabled: dis, isInvalid })}>
							{isSelected && <div className={styles.dot} />}
						</div>
						{label}
					</>
				)}
			</RadioButton>
		</RadioField>
	)
}

import type { ReactNode } from "react"
import { useContext, useEffect } from "react"
import { FieldError, Label, RadioGroup as RACRadioGroup, Text } from "react-aria-components"
import { FormStateContext } from "../../form-state"
import { getRadioGroupStyles } from "./radio.styles"

interface RadioGroupProps {
	readonly label?: string
	readonly value?: string
	readonly defaultValue?: string
	readonly isDisabled?: boolean
	readonly isRequired?: boolean
	readonly isReadOnly?: boolean
	readonly isInvalid?: boolean
	readonly validationBehavior?: "aria" | "native"
	readonly validate?: (value: string) => string | string[] | true | null | undefined
	readonly orientation?: "horizontal" | "vertical"
	readonly name?: string
	readonly description?: string
	readonly errorMessage?: string
	readonly onChange?: (value: string) => void
	readonly children?: ReactNode
}

export function RadioGroup({
	label,
	value,
	defaultValue,
	isDisabled = false,
	isRequired = false,
	isReadOnly = false,
	isInvalid = false,
	validationBehavior,
	validate,
	orientation = "vertical",
	name,
	description,
	errorMessage,
	onChange,
	children,
}: RadioGroupProps) {
	const styles = getRadioGroupStyles()
	const formCtx = useContext(FormStateContext)

	// biome-ignore lint/correctness/useExhaustiveDependencies: intentional mount-only seed
	useEffect(() => {
		if (defaultValue !== undefined && label) formCtx?.setValue(label, defaultValue)
	}, [])

	const handleChange = (v: string) => {
		if (label) formCtx?.setValue(label, v)
		onChange?.(v)
	}

	return (
		<RACRadioGroup
			value={value}
			defaultValue={defaultValue}
			isDisabled={isDisabled}
			isRequired={isRequired}
			isReadOnly={isReadOnly}
			isInvalid={isInvalid}
			validationBehavior={validationBehavior}
			validate={validate}
			orientation={orientation}
			name={name}
			onChange={handleChange}
			className={styles.group}
		>
			{label && <Label className={styles.label}>{label}</Label>}
			<div className={styles.items(orientation)}>{children}</div>
			{description && (
				<Text slot="description" className={styles.description}>
					{description}
				</Text>
			)}
			<FieldError className={styles.errorMessage}>{errorMessage}</FieldError>
		</RACRadioGroup>
	)
}

interface IndicatorState {
	isSelected: boolean
	isDisabled?: boolean
	isInvalid?: boolean
}

const indicatorBase = "w-4 h-4 shrink-0 rounded-full border-2 flex items-center justify-center transition-colors"

export const getRadioStyles = () => ({
	field: "flex flex-col gap-1",
	button: "flex items-center gap-2 text-sm text-(--color-text) cursor-pointer select-none",
	indicator({ isSelected, isDisabled, isInvalid }: IndicatorState) {
		if (isDisabled) {
			return `${indicatorBase} bg-(--color-backgroundMuted) border-(--color-border) opacity-50`
		}
		if (isSelected) {
			return `${indicatorBase} bg-(--color-background) border-(--color-primary)`
		}
		if (isInvalid) {
			return `${indicatorBase} bg-(--color-background) border-(--color-danger)`
		}
		return `${indicatorBase} bg-(--color-background) border-(--color-border)`
	},
	dot: "w-2 h-2 rounded-full bg-(--color-primary)",
})

export const getRadioGroupStyles = () => ({
	group: "flex flex-col gap-2",
	label: "text-sm font-medium text-(--color-text)",
	items: (orientation: "horizontal" | "vertical" = "vertical") =>
		orientation === "horizontal" ? "flex flex-row flex-wrap gap-4" : "flex flex-col gap-2",
	description: "text-xs text-(--color-textMuted)",
	errorMessage: "text-xs text-(--color-danger)",
})
